import os
import subprocess

def generate_requirements():
    """
    Function to generate a requirements.txt file with hashes.
    """

    print("Generating requirements.txt ...")

    try:
        os.remove('requirements.txt')
    except FileNotFoundError:
        pass

    subprocess.check_call([r'pip', 'freeze', '>', 'requirements.txt'], shell=True)

    print("requirements.txt has been generated.")

def pip_install(package_name):
    """
    Install the package and update the requirements.txt
    """

    try:
        subprocess.check_call([r'pip', 'install', package_name], shell=True)
        generate_requirements()
    except Exception as e:
        print(f"Error occurred: {str(e)}.")

def pip_uninstall(package_name):
    """
    Uninstall the package and update the requirements.txt
    """

    try:
        subprocess.check_call([r'pip', 'uninstall', '-y', package_name], shell=True)
        generate_requirements()
    except Exception as e:
        print(f"Error occurred: {str(e)}.")

# For generating poetry.lock using Poetry

def generate_poetry_lock():
    """
    Function to generate a poetry.lock file after installing dependencies using poetry.
    """

    print("Generating poetry.lock ...")

    try:
        os.remove('poetry.lock')
    except FileNotFoundError:
        pass

    subprocess.check_call([r'poetry', 'lock'], shell=True)

    print("poetry.lock has been generated.")

